export const games = apps;

export function getFeaturedGame(tabId = "experiments") {
  return apps.find((app) => app.tab === tabId && app.featured) ?? apps.find((app) => app.tab === tabId) ?? apps[0] ?? null;
}

export function getGameById(id) {
  return apps.find((app) => app.id === id) ?? null;
}
